import { Injectable } from '@angular/core';
import { HttpClient, HttpParams } from '@angular/common/http';
import { Observable } from 'rxjs';
import { environment } from '../../environments/environment';
import { EventItem, Rsvp, User, Venue } from './models';

/**
 * GatherUp API client. Typed against models.ts and the surface contract.
 * The mockup pages render local signal mock data; the service_agent stage
 * wires these methods into the page components via ngOnInit().
 */
@Injectable({ providedIn: 'root' })
export class ApiService {
  private readonly base = environment.apiUrl;

  constructor(private http: HttpClient) {}

  // ---- Users ----
  me(): Observable<User> {
    return this.http.get<User>(`${this.base}/users/me`);
  }

  // ---- Events (public reads) ----
  listEvents(q?: string, category?: string, upcoming?: boolean): Observable<EventItem[]> {
    let params = new HttpParams();
    if (q) params = params.set('q', q);
    if (category) params = params.set('category', category);
    if (upcoming) params = params.set('upcoming', 'true');
    return this.http.get<EventItem[]>(`${this.base}/events`, { params });
  }
  getEvent(id: string): Observable<EventItem> {
    return this.http.get<EventItem>(`${this.base}/events/${id}`);
  }
  createEvent(body: Partial<EventItem>): Observable<EventItem> {
    return this.http.post<EventItem>(`${this.base}/events`, body);
  }
  updateEvent(id: string, body: Partial<EventItem>): Observable<EventItem> {
    return this.http.patch<EventItem>(`${this.base}/events/${id}`, body);
  }
  deleteEvent(id: string): Observable<void> {
    return this.http.delete<void>(`${this.base}/events/${id}`);
  }

  // ---- Venues (public reads, organizer writes) ----
  listVenues(): Observable<Venue[]> {
    return this.http.get<Venue[]>(`${this.base}/venues`);
  }
  getVenue(id: string): Observable<Venue> {
    return this.http.get<Venue>(`${this.base}/venues/${id}`);
  }
  createVenue(body: Partial<Venue>): Observable<Venue> {
    return this.http.post<Venue>(`${this.base}/venues`, body);
  }
  updateVenue(id: string, body: Partial<Venue>): Observable<Venue> {
    return this.http.patch<Venue>(`${this.base}/venues/${id}`, body);
  }
  deleteVenue(id: string): Observable<void> {
    return this.http.delete<void>(`${this.base}/venues/${id}`);
  }

  // ---- RSVP (any logged-in user) ----
  rsvp(eventId: string): Observable<Rsvp> {
    return this.http.post<Rsvp>(`${this.base}/events/${eventId}/rsvp`, {});
  }
  cancelRsvp(eventId: string): Observable<Rsvp> {
    return this.http.delete<Rsvp>(`${this.base}/events/${eventId}/rsvp`);
  }
  myEvents(): Observable<Rsvp[]> {
    return this.http.get<Rsvp[]>(`${this.base}/rsvp/mine`);
  }

  // ---- Organizer: attendees + check-in ----
  eventAttendees(eventId: string): Observable<Rsvp[]> {
    return this.http.get<Rsvp[]>(`${this.base}/events/${eventId}/attendees`);
  }
  toggleCheckin(eventId: string, userId: string): Observable<Rsvp> {
    return this.http.patch<Rsvp>(
      `${this.base}/events/${eventId}/attendees/${userId}/checkin`,
      {},
    );
  }
}
